#include<bits/stdc++.h>
using namespace std;
int col[201],len[201],dp[201][201][551];
int now,lst,tot;
int dfs(int l,int r,int k)
{
    if(dp[l][r][k]!=0)
    {
        return dp[l][r][k];
    }
    if(l==r)
    {
        return (len[l]+k)*(len[l]+k);
    }
    dp[l][r][k]=dfs(l,r-1,0)+(len[r]+k)*(len[r]+k);
    for(int i=l;i<r-1;i++)
    {
        if(col[i]==col[r])
        {
            dp[l][r][k]=max(dp[l][r][k],dfs(l,i,len[r]+k)+dfs(i+1,r-1,0));
        }
    }
    return dp[l][r][k];
}
int main()
{
    int t;
    scanf("%d",&t);
    for(int _case=1;_case<=t;_case++)
    {
        int n;
        scanf("%d",&n);
        memset(dp,0,sizeof(dp));
        memset(col,0,sizeof(col));
        memset(len,0,sizeof(len));
        tot=0;
        lst=-1;
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&now);
            if(now==lst)
            {
                len[tot]++;
            }
            else
            {
                col[++tot]=now;
                len[tot]++;
                lst=now;
            }
        }
        printf("Case %d: %d\n",_case,dfs(1,tot,0));
    }
    return 0;
}
